+  /** Apply declared config values as the lowest-precedence option source. */
+  private applyConfig(ctx: ParseContext): void {
+    for (const option of this.getOptions(true)) {
+      const key = configKey(option.name);
+      const value = this.getConfigValues()[key];
+      if (typeof value === "undefined" || Object.hasOwn(ctx.env, key)) continue;
+
+      try {
+        ctx.env[key] = this.parseConfigOption(option, value, key);
+      } catch (error) {
+        if (error instanceof ConfigValidationError) throw error;
+        throw new ConfigValidationError(
+          key,
+          error instanceof Error ? error.message : String(error),
+        );
+      }
