+  private parseConfigOption(option: Option, value: unknown, key: string): unknown {
+    if (Array.isArray(value)) {
+      if (!option.collect) {
+        throw new ConfigValidationError(key, "option does not accept an array.");
+      }
+      return value.map((item) => this.parseConfigValue(option, item, key));
+    }
+    if (option.collect) {
+      throw new ConfigValidationError(key, "collect option requires an array.");
+    }
+    return this.parseConfigValue(option, value, key);
+  }
