+  private parseConfigValue(option: Option, value: unknown, key: string): unknown {
+    const type = option.args[0]?.type;
+    if (!type) {
+      if (typeof value !== "boolean") {
+        throw new ConfigValidationError(key, "expected a boolean.");
+      }
+      return option.value ? option.value(value) : value;
+    }
+    if (type === "number" || type === "integer") {
+      if (typeof value !== "number" || !Number.isFinite(value)) {
+        throw new ConfigValidationError(key, `expected a ${type}.`);
+      }
+    } else if (type === "boolean" && typeof value !== "boolean") {
+      throw new ConfigValidationError(key, "expected a boolean.");
+    } else if ((type === "string" || type === "file" || type === "secret") &&
+      typeof value !== "string") {
+      throw new ConfigValidationError(key, "expected a string.");
+    }
+    const parsed = this.parseType({
+      label: "Config value",
+      type,
+      name: key,
+      value: String(value),
+    });
