+
+async function withTempDir(fn: (path: string) => Promise<void>) {
+  const path = await Deno.makeTempDir();
+  try {
+    await fn(path);
+  } finally {
+    await Deno.remove(path, { recursive: true });
+  }
+}
+
+test({ name: "[command] config: loads, flattens, and caches JSON config", fn: async () => {
+  await withTempDir(async (path) => {
+    await Deno.writeTextFile(
+      `${path}/app.json`,
+      JSON.stringify({
+        "foo-bar": "config",
+        count: 0,
+        enabled: false,
+        tags: ["one", "two"],
+        nested: { value: "flattened" },
+        ignored: "value",
