+    const command = new Command()
+      .throwErrors()
+      .config({ name: "app", searchPaths: [path] })
+      .option("--foo-bar <value:string>", "")
+      .option("--count <value:number>", "")
+      .option("--enabled", "")
+      .option("--tags <value:string>", "", { collect: true })
+      .option("--nested.value <value:string>", "");
