+import { resolve } from "@std/path";
+import { ConfigParseError } from "./errors.ts";
+import type { ConfigOptions } from "./types.ts";
+
+export interface LoadedConfig {
+  path?: string;
+  values: Record<string, unknown>;
+}
+
+/** Load the configuration files described by options. */
+export async function loadConfig(
+  options: ConfigOptions,
+): Promise<LoadedConfig> {
+  const searchPaths = options.searchPaths ?? [Deno.cwd()];
+  const formats = options.formats ?? [".json", ".rc"];
+  const matches: Array<{ path: string; format: string }> = [];
+
+  for (const searchPath of searchPaths) {
+    for (const format of formats) {
+      const path = resolve(searchPath, configFileName(options.name, format));
+      try {
+        const stat = await Deno.stat(path);
+        if (stat.isFile) matches.push({ path, format });
+      } catch (error) {
+        if (!(error instanceof Deno.errors.NotFound)) throw error;
+      }
+    }
+  }
+
+  if (!options.mergeConfigs) matches.splice(1);
+
+  const values: Record<string, unknown> = {};
+  // Later assignments have lower priority: paths earlier in searchPaths win.
+  for (const match of matches.slice().reverse()) {
+    const content = await Deno.readTextFile(match.path);
+    const parsed = parseConfig(
+      content,
+      match.path,
+      match.format,
+      options.parser,
+    );
+    Object.assign(values, flattenConfig(parsed));
+  }
+
+  return { path: matches[0]?.path, values };
+}
+
+function configFileName(name: string, format: string): string {
+  return format === ".rc" ? `.${name}rc` : `${name}${format}`;
+}
+
+function parseConfig(
+  content: string,
+  path: string,
+  format: string,
+  parser?: ConfigOptions["parser"],
+): Record<string, unknown> {
+  try {
+    const value = parser
+      ? parser(content)
+      : format === ".json"
+      ? JSON.parse(content)
+      : parseRc(content);
+    if (!isPlainObject(value)) {
+      throw new TypeError("Config must contain an object.");
+    }
+    return value;
+  } catch (error) {
+    throw new ConfigParseError(path, error);
+  }
+}
+
+function parseRc(content: string): Record<string, unknown> {
+  const result: Record<string, unknown> = {};
+  for (const line of content.split(/\r?\n/)) {
+    const trimmed = line.trim();
+    if (!trimmed || trimmed.startsWith("#")) continue;
+    const match = /^([^=\s]+)\s*=\s*(.*?)\s*$/.exec(line);
+    if (!match) throw new TypeError(`Invalid RC entry: ${line}`);
+    const [, key, rawValue] = match;
+    const quoted = /^"(.*)"$/.exec(rawValue);
+    const value = quoted ? quoted[1] : rawValue.trim();
+    result[key] = quoted ? value : coerceRcValue(value);
+  }
+  return result;
+}
+
+function coerceRcValue(value: string): string | number | boolean {
+  if (value === "true") return true;
+  if (value === "false") return false;
+  if (value !== "" && /^[-+]?(?:\d+\.?\d*|\.\d+)$/.test(value)) {
+    return Number(value);
+  }
+  return value;
+}
+
+function flattenConfig(
+  value: Record<string, unknown>,
+  prefix = "",
+  result: Record<string, unknown> = {},
+): Record<string, unknown> {
+  for (const [key, child] of Object.entries(value)) {
+    const name = prefix ? `${prefix}.${key}` : key;
+    if (isPlainObject(child)) flattenConfig(child, name, result);
+    else result[toCamelCase(name)] = child;
+  }
+  return result;
+}
+
+function toCamelCase(value: string): string {
+  return value.replace(
+    /-([a-zA-Z0-9])/g,
+    (_match, char: string) => char.toUpperCase(),
+  );
+}
+
+function isPlainObject(value: unknown): value is Record<string, unknown> {
+  return !!value && typeof value === "object" &&
+    (Object.getPrototypeOf(value) === Object.prototype ||
+      Object.getPrototypeOf(value) === null);
+}
