+import { CommandError } from "../_errors.ts";
+
+/** Thrown when a configuration file cannot be parsed. */
+export class ConfigParseError extends CommandError {
+  constructor(path: string, cause?: unknown) {
+    super(
+      `Failed to parse config file "${path}".${
+        cause
+          ? ` ${cause instanceof Error ? cause.message : String(cause)}`
+          : ""
+      }`,
+    );
+    this.name = "ConfigParseError";
+    Object.setPrototypeOf(this, ConfigParseError.prototype);
+  }
+}
+
+/** Thrown when a configuration value cannot be used by an option. */
+export class ConfigValidationError extends CommandError {
+  constructor(key: string, message: string) {
+    super(`Invalid config value for "${key}": ${message}`);
+    this.name = "ConfigValidationError";
+    Object.setPrototypeOf(this, ConfigValidationError.prototype);
+  }
+}
